  ('real-estate-moex-02473', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '繼承人有數人時，在分割遺產前，各繼承人對於遺產之所有型態為：', '["按其應有部分各自擁有單獨所有權", "按應繼分比例分別共有遺產", "按應有部分比例分別共有遺產", "公同共有遺產"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02474', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '繼承人於繼承開始前已從被繼承人受有贈與而應予歸扣之財產，不包括下列何者？', '["因結婚所為之贈與", "因分居所為之贈與", "因營業所為之贈與", "因扶養所為之贈與"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02475', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲有配偶乙及子女丙、丁、戊三人，丙已婚育有子女己、庚二人。設丙拋棄繼承，則甲之遺產應如何分配？', '["乙丁戊各分得遺產之三分之一", "乙分得遺產之二分之一，丁戊各得四分之一", "乙分得遺產之二分之一，丁戊己庚則各得八分之一", "乙丁戊己庚各得遺產之五分之一"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02476', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於遺產之分割，下列敘述何者錯誤？', '["被繼承人以遺囑禁止遺產分割者，其禁止效力以十年為限", "繼承人中有胎兒時，須俟胎兒出生後始得分割遺產", "遺產分割後，各繼承人按其所得部分對他繼承人負有與出賣人同一之擔保責任", "繼承人對已屆清償期之繼承債務之連帶責任，自遺產分割時起經五年而免除"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02477', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於夫妻財產制之約定，下列敘述何者錯誤？', '["夫妻於結婚前或結婚後均得就本法所定之三種約定財產制中，包括共同財產制、聯合財產制及分別財 產制中選擇其一為夫妻財產制", "夫妻財產制契約之訂定及變更、廢止，乃要式行為，應以書面為之，否則不生效力", "夫妻財產制契約之訂定及變更、廢止，若未辦理登記仍生效力，僅不得以之對抗第三人", "夫妻之一方受破產宣告時，則當然改為分別財產制"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02478', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於法定財產制中之婚後財產之範圍，下列敘述何者錯誤？', '["夫妻於婚姻關係存續中所取得之財產為婚後財產", "夫或妻之婚前財產，於婚姻關係中所生之孳息，視為婚後財產", "不能證明為婚前或婚後財產者，推定為婚後財產", "約定夫妻財產制契約後，於婚姻關係存續中改用法定財產制者，其改用前之財產視為婚後財產"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02479', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於身分法上年齡規定之敘述，下列何者錯誤？', '["訂定婚約之年齡，男女各為17歲及15歲", "結婚之年齡，男女各為18歲及16歲", "收養者之年齡應長於被收養者20歲以上，但夫妻之一方收養他方之子女時，應長於被收養者18歲以上", "滿16歲以上即具有訂立遺囑之能力而無須得其法定代理人之同意"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
