  ('real-estate-moex-02481', 'real-estate', 'real-estate-moex-098-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '否認婚生子女之訴，下列何人無權提起？', '["夫", "妻", "子女本人", "子女之生父"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "b014528585ac", "answer_pdf_sha1": "113f68396279", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
